	&lt;p data-end=&quot;625&quot; data-start=&quot;531&quot;&gt;&lt;strong data-end=&quot;544&quot; data-start=&quot;531&quot;&gt;Location:&lt;/strong&gt; &lt;strong data-end=&quot;560&quot; data-start=&quot;545&quot;&gt;Kaleshwaram&lt;/strong&gt; (कालेस्वरम), &lt;strong data-end=&quot;601&quot; data-start=&quot;574&quot;&gt;Jayashankar Bhupalpally&lt;/strong&gt; district, &lt;strong data-end=&quot;625&quot; data-start=&quot;612&quot;&gt;Telangana&lt;/strong&gt;&lt;/p&gt;
