	&lt;/li&gt;
	&lt;li data-end=&quot;758&quot; data-start=&quot;688&quot;&gt;
	&lt;p data-end=&quot;758&quot; data-start=&quot;690&quot;&gt;&lt;strong data-end=&quot;708&quot; data-start=&quot;690&quot;&gt;River Worship:&lt;/strong&gt; Dedicated to the &lt;strong data-end=&quot;758&quot; data-start=&quot;726&quot;&gt;subterranean Saraswati River&lt;/strong&gt;&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;916&quot; data-start=&quot;759&quot;&gt;
	&lt;p data-end=&quot;841&quot; data-start=&quot;761&quot;&gt;&lt;strong data-end=&quot;776&quot; data-start=&quot;761&quot;&gt;Confluence:&lt;/strong&gt; At &lt;strong data-end=&quot;800&quot; data-start=&quot;780&quot;&gt;Triveni Sangamam&lt;/strong&gt; (त्रिवेनी सँगमम) &amp;ndash; the meeting point of:&lt;/p&gt;

	&lt;ul data-end=&quot;916&quot; data-start=&quot;844&quot;&gt;
		&lt;li data-end=&quot;859&quot; data-start=&quot;844&quot;&gt;
		&lt;p data-end=&quot;859&quot; data-start=&quot;846&quot;&gt;&lt;strong data-end=&quot;859&quot; data-start=&quot;846&quot;&gt;Saraswati&lt;/strong&gt;&lt;/p&gt;
		&lt;/li&gt;
		&lt;li data-end=&quot;886&quot; data-start=&quot;862&quot;&gt;
		&lt;p data-end=&quot;886&quot; data-start=&quot;864&quot;&gt;&lt;strong data-end=&quot;876&quot; data-start=&quot;864&quot;&gt;Godavari&lt;/strong&gt; (गोदावरी)&lt;/p&gt;
